+    const info = resolveContextWindowInfo({
+      cfg: undefined,
+      provider: "openrouter",
+      modelId: "tiny",
+      modelContextWindow: 8000,
+      defaultTokens: 200_000,
+    });
+    const guard = evaluateContextWindowGuard({ info });
